/* Suggested markup: <div class="uiwiki-scroll-snap-process-cards" tabindex="0"><span>Scroll Snap Process Cards</span></div> */
.uiwiki-scroll-snap-process-cards {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-scroll-snap-process-cards > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #53e8d4;
  animation: scroll_snap_process_cards 1.8s ease-in-out infinite alternate;
}
.uiwiki-scroll-snap-process-cards:hover,
.uiwiki-scroll-snap-process-cards:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes scroll_snap_process_cards {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-scroll-snap-process-cards, .uiwiki-scroll-snap-process-cards > span { animation: none; transition: none; }
}
